/**
 * breathing-led - LED 呼吸灯示例
 * 
 * 功能：
 *   - PWM 控制的 LED 呼吸效果
 *   - 按键切换呼吸速度（3档）
 *   - 串口实时输出状态
 */

#include <stdio.h>
#include "board.h"
#include "gpio.h"
#include "timer.h"
#include "uart.h"

/* ---- 常量定义 ---- */
#define LED_PIN         GPIO_PIN_13    /* 蓝色 LED */
#define BTN_PIN         GPIO_PIN_0     /* 用户按键 */
#define PWM_PERIOD      1000           /* PWM 周期 (us) */
#define BREATH_STEPS    100            /* 呼吸步数 */

/* 呼吸速度档位（ms/step） */
typedef enum {
    SPEED_SLOW   = 30,   /* 慢速 ~3s/周期 */
    SPEED_MEDIUM = 15,   /* 中速 ~1.5s/周期 */
    SPEED_FAST   = 5     /* 快速 ~0.5s/周期 */
} breath_speed_t;

/* ---- 全局状态 ---- */
static breath_speed_t g_speed = SPEED_MEDIUM;
static uint32_t       g_step  = 0;
static uint8_t        g_dir   = 1;    /* 1=变亮, 0=变暗 */
static uint32_t       g_last_tick = 0;

/* ---- 函数声明 ---- */
void system_init(void);
void breath_update(void);
void button_check(void);
void uart_print_status(void);

/* ---- 入口函数 ---- */
int main(void)
{
    system_init();
    printf("\n=== Breathing LED Demo ===\n");
    printf("Press the USER button to change speed.\n\n");

    while (1) {
        breath_update();
        button_check();
    }

    return 0;
}

/* ---- 系统初始化 ---- */
void system_init(void)
{
    board_init();
    uart_init(USART1, 115200);

    /* 配置 LED 为 PWM 输出 */
    gpio_init(LED_PIN, GPIO_MODE_AF_PP);
    timer_pwm_init(TIM2, 1, PWM_PERIOD);

    /* 配置按键为输入（内部上拉） */
    gpio_init(BTN_PIN, GPIO_MODE_INPUT_PU);

    /* 配置 1ms SysTick */
    timer_init(TIM6, 1000);

    g_last_tick = timer_get_ms();
    printf("[INIT] System initialized OK\n");
}

/* ---- 呼吸灯更新 ---- */
void breath_update(void)
{
    uint32_t now = timer_get_ms();

    if (now - g_last_tick < (uint32_t)g_speed) {
        return;
    }
    g_last_tick = now;

    /* 计算当前占空比（正弦近似） */
    if (g_dir) {
        g_step++;
        if (g_step >= BREATH_STEPS) {
            g_step = BREATH_STEPS;
            g_dir = 0;
        }
    } else {
        g_step--;
        if (g_step == 0) {
            g_dir = 1;
        }
    }

    /* 将步数映射到 PWM 占空比 (0-100%) */
    uint32_t duty = (g_step * PWM_PERIOD) / BREATH_STEPS;
    timer_pwm_set_duty(TIM2, 1, duty);
}

/* ---- 按键检测（简单去抖动） ---- */
void button_check(void)
{
    static uint32_t last_press = 0;
    uint32_t now = timer_get_ms();

    /* 50ms 去抖动 */
    if (now - last_press < 50) {
        return;
    }

    if (gpio_read(BTN_PIN) == GPIO_LOW) {
        last_press = now;

        /* 循环切换速度 */
        switch (g_speed) {
            case SPEED_SLOW:   g_speed = SPEED_MEDIUM; break;
            case SPEED_MEDIUM: g_speed = SPEED_FAST;   break;
            case SPEED_FAST:   g_speed = SPEED_SLOW;   break;
        }

        uart_print_status();
    }
}

/* ---- 串口状态输出 ---- */
void uart_print_status(void)
{
    const char *speed_str = "Unknown";
    switch (g_speed) {
        case SPEED_SLOW:   speed_str = "Slow";   break;
        case SPEED_MEDIUM: speed_str = "Medium";  break;
        case SPEED_FAST:   speed_str = "Fast";    break;
    }
    printf("[BTN] Speed changed to: %s\n", speed_str);
}

/* 使用正弦函数的呼吸效果（更自然） */
#include <math.h>

void breath_update_sine(void)
{
    uint32_t now = timer_get_ms();
    uint32_t elapsed = now - g_start_time;

    /* sin(0) 到 sin(pi)，范围 [0, 1] */
    float phase = (float)(elapsed % g_period) / (float)g_period;
    float brightness = sinf(phase * 3.14159265f);

    uint32_t duty = (uint32_t)(brightness * PWM_PERIOD);
    timer_pwm_set_duty(TIM2, 1, duty);
}
